import Nav from "../components/nav";
import Record from "../components/record";
import { getAll, insert, createUseDb } from "../lib/db";
import {sync} from "../lib/sync";

const persistedState = createUseDb("my-group");

export default function Home() {
  const [records, insertRecord] = persistedState("records");
  return (
    <div>
      <Nav />
      <main>
        <h1>Welcome to Contatempo. Records: {records.length}</h1>
        <button
          onClick={() => {
            const newRecord = {
              start: new Date().toISOString(),
              end: new Date(2020, 12, 1).toISOString(),
            };
            insertRecord(newRecord);
          }}
        >
          Add
        </button>
        <button onClick={()=> sync()}>Sync</button>
        <ul>
          {records.map((record) => (
            <Record key={record.start} record={record} />
          ))}
        </ul>
      </main>
    </div>
  );
}
